var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"면목 없군. 이번에도 그 여잘 이기지 못했어.","JPN":"面目ない。今回も彼女に勝てなかった。","ENG":"I have no excuse. I couldn't win against Yeonhwa again.","TWN":"真抱歉。這一次，我又輸給了蓮華。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"두 명이었다.","JPN":"2人だった。","ENG":"There were two of them.","TWN":"有兩個人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"<color=#ffd34c>범</color>을 잡겠다는 사람이… 그 연화라는 여자 말고도 한 사람 더 있었어.","JPN":"<color=#ffd34c>虎</color>を倒そうとするやつが……そのレンカって女の他にも、もう一人いた。","ENG":"It wasn't just Yeonhwa who wanted to hunt the <color=#ffd34c>Tiger</color>… There was also someone else.","TWN":"除了那個叫蓮華的女人，還有另一個人，也說要抓老虎。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…둘이었다고?","JPN":"……2人？","ENG":"…Two, you say?","TWN":"…兩個人？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나도 똑똑히 들었어. 어르신은 그 사람을 아버지라고 불렀지?","JPN":"私も確かに聞いたよ。あの人、おばあさんのお父さんなんだよね？","ENG":"I heard it clearly too. You called him \\"Father,\\" right, granny?","TWN":"我也聽得清清楚楚。阿姨叫那個人父親吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 사람도 자기 입으로 그렇다고 했고.","JPN":"あの人も認めていたし。","ENG":"And he said it himself.","TWN":"那個人自己也說是。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 얼굴도 기억하겠군!","JPN":"なら、顔も覚えているのだな！","ENG":"Then you must remember his face!","TWN":"那麽，你應該也記得他的長相吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"수소문해서 그를 찾아보면 어떤가! 만나면 우리가 모르는 정보를 얻을 수 있을 테니…!","JPN":"聞き込みをして彼を探してみるのはどうだ！　会えれば我らが知らない情報を聞くこともできるはず……！","ENG":"What if we tracked him down? We might learn something we don't already know…!","TWN":"去打聽一下，試著找找他怎麼樣！如果見面了，或許能得到我們不知道的資訊…！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"살아있는 사람은 아닐 거다.","JPN":"既にこの世にはいない人間だろう。","ENG":"He's probably not alive anymore.","TWN":"他大概不在人世了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거에선 분명히 느껴졌던 그 사람의 존재가… 지금 이곳에선 느껴지지 않거든.","JPN":"過去でははっきりと感じたあの人の存在が、ここではまったく感じられない。","ENG":"The presence I once felt so clearly in the past… I can’t feel it here anymore.","TWN":"在過去，我明明能清楚感覺到那個人的存在…但在這裡，我感覺不到他的存在。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"미안하군. 내가 너무 성급했네.","JPN":"すまない。某が性急すぎた。","ENG":"My apologies. I got ahead of myself.","TWN":"抱歉。我太著急了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"죽었을 거라고 짐작은 했어.","JPN":"死んでいるだろうとは予想はしていた。","ENG":"I figured as much.","TWN":"我猜他應該已經死了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래도… 당신의 장치가 없었다면 과거에서조차 만나지 못했을 테지.","JPN":"だが……お前の装置がなかったら、過去ですら会うことはできなかっただろう。","ENG":"Still… without your device, I never would've met him, not even in the past.","TWN":"不過…如果沒有你的裝置，我連在過去也無法見到他吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 어렴풋하던 얼굴을 직접 본 것만으로도 나쁘진 않았어.","JPN":"薄っすらとしか思い出せなかった顔を実際見れただけでも、まあ悪くはなかった。","ENG":"I'm glad I got to see his face, even just once.","TWN":"光是親眼見到那個模糊的長相，就已經不錯了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거로 돌아가는 건 이번이 마지막이 아닐세.","JPN":"過去に戻るのはこれが最後ではない。","ENG":"That won't be our last time returning to the past.","TWN":"這次不會是最後一次回到過去。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화의 일행이라면 분명 나와도 무관하진 않을 테니. 할 수만 있다면 두 사람 모두를 돕겠다고 약속하지.","JPN":"レンカの仲間なら某とも無関係ではない。2人がまた会えるように、最善を尽くすと約束しよう。","ENG":"If he was with Yeonhwa, then I have a connection to him too. If I can, I'll do everything I can to help them both.","TWN":"既然是蓮華的同伴，那也和我脫不了關係。如果可以，我答應會幫助他們兩個人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"…Yeah.","TWN":"…好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 사람을 다시 만날 수 있다면, 나도 당신을 전력으로 돕겠어.","JPN":"あの人にまた会えるなら、私もお前を全力で手伝う。","ENG":"If there's a chance I could see him again, I'll back you with everything I've got.","TWN":"如果能再次見到那個人，我也會全力幫助你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"라고 멋지게 결의를 다졌지만, 모아둔 이터니움이 이번에 완전히 바닥났습니다.","JPN":"……と、カッコよく決意表明しましたが、集めておいたエタニウムが底をついてしまいましたよ。","ENG":"Well, dramatic vows aside, we're totally out of Eternium.","TWN":"說得這麼帥氣，但我收集的永恆之金這次徹底用光了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"과.위.장을 가동하려면 다시 그 많은 양을 구해야 할 텐데, 쉽진 않겠네.","JPN":"過向装を稼働するにはまたあの量を集めないといけないけど、骨が折れるね。","ENG":"And we'll need a lot more if we're using DTP again. That won't be easy.","TWN":"要啟動回裝置，又要再找那麼多永恆之金，這可不容易。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돈을 마련할 수단이라면 있다.","JPN":"金を調達する手段ならある。","ENG":"I have a way to get us funds.","TWN":"我有辦法籌錢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"우리가 동굴에서 찾은 거 말이야.","JPN":"私たちが洞窟で見つけたあれだ。","ENG":"Remember what we found in the cave?","TWN":"我們在洞穴裡找到的那個。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응? 설마 차원함선 말하는 거야? 그걸 팔기라도 하자고?","JPN":"うん？　まさか次元艦船のこと？　あれを売るの？","ENG":"Huh? You mean the dimensional ship? You want to sell that thing?","TWN":"嗯？你說的是次元艦船嗎？把它賣掉？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이터니움 드라이브는 못 팔아도, 그 밖에 쓸만한 부품을 건질 순 있겠지.","JPN":"エタニウムドライブは売れなくても、他に使えそうな部品は手に入るだろう。","ENG":"Even if we can't sell the Eternium Drive, we can salvage useful parts.","TWN":"就算賣不掉永恆之金驅動器，也能從裡面找到其他有用的零件吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기요. 관리국 출신이던 사람들이 그런 말 해도 돼?","JPN":"ちょっと、管理局出身の人がそんなこと言っていいの？","ENG":"Hey, are ex-Administration officials even allowed to say stuff like that?","TWN":"喂。你們兩個管理局出身的人說這種話，好嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"혹시 모르잖나. 어쩌면 우리가 모르는 과거에 대한 단서를 그곳에서 찾을 수도 있으니까.","JPN":"井戸の近くで見つけたものであるし、我らがまだ知らない過去の手がかりが見つかるかもしれんな。","ENG":"You never know. We might find clues about a past we don’t yet understand there.","TWN":"說不定呢。或許我們能在裡面找到我們不知道的，關於過去的線索。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"주변을 탐색하는 데 도움이 될만한 탐지용 장비를 몇 개 가져왔네.","JPN":"周辺の探索に役立ちそうな装備をいくつか持ってきた。","ENG":"I brought a few detection tools to help us scout the area.","TWN":"我帶了一些有助於探索的探測設備。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_13"},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지수 양은 무엇을 쓰겠나?","JPN":"シノ君は何を使う？","ENG":"Jisoo, want to try using one?","TWN":"智秀，你要用哪一個？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"됐어.","JPN":"遠慮する。","ENG":"No thanks.","TWN":"不用了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 그걸 써봐야 망가뜨리기만 할 테니, 직접 눈으로 찾아보지.","JPN":"私が使ったところで壊すだけだし、直接目で見て探すさ。","ENG":"I'd just break it. I'll use my eyes instead.","TWN":"我用那東西只會把它弄壞，我還是用眼睛找吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 난 함교에서 멀쩡한 데이터 뱅크가 있는지 확인해볼게.","JPN":"じゃあ私は艦橋で、無事なデータバンクがないか確かめてみるよ。","ENG":"Then I'll go check if the bridge has a working data bank.","TWN":"那我去艦橋看看有沒有還能用的資料庫。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…말은 그렇게 했지만, 이런 첨단기술의 집약체 같은 건 만져본 적도 없는데.","JPN":"……といったものの、こんな先端技術のかたまり、触ったこともないんだよね。","ENG":"…Though honestly, I've never touched anything this high-tech like this before.","TWN":"…話是這麼說，但我從來沒碰過這種高科技的東西。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐, 이것저것 누르다 보면 뭐라도 나오겠지.","JPN":"まあ、適当に押してみたらなんか出てくるでしょ。","ENG":"Meh, I'll just start pressing buttons and see what happens.","TWN":"不過，東按按西按按，總會找到點什麼吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아무런 정보도 찾지 못했다고?","JPN":"何の情報も見つからなかった？","ENG":"You didn't find anything?","TWN":"什麼資訊都沒找到？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하나도 없었어.","JPN":"な～んにもなかった。","ENG":"Not a single thing.","TWN":"一點都沒有。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"항행기록조차 없는 텅 빈 깡통이더라. 누가 일부러 지우기라도 한 것처럼.","JPN":"航行記録すら残ってなかったよ。まるで誰かがわざと消したみたいに。","ENG":"Even the navigation logs were wiped. Like someone scrubbed it on purpose.","TWN":"是個連航行記錄都沒有的空殼。就像被誰故意刪除了一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런가. 아쉽게 됐군.","JPN":"そうか。残念であるな。","ENG":"I see. That's unfortunate.","TWN":"是嗎。真可惜。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이쪽도 수확이라기엔 변변찮은 걸세.","JPN":"こちらも収穫と呼ぶにはお粗末だが。","ENG":"Not much luck on my end either.","TWN":"我這邊也沒什麼收穫。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"오래된 수첩 한 권이다.","JPN":"古びた手帳を1冊見つけた。","ENG":"Just one old notebook.","TWN":"只找到一本舊筆記本。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"수첩? 별로 비싸 보이진 않네.","JPN":"手帳？　高そうには見えないけど。","ENG":"A notebook? Doesn't look like it's worth much.","TWN":"筆記本？看起來不怎麼值錢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돈 되는 것 보단 정보를 찾는 줄 알았는데.","JPN":"金になるものじゃなくて、情報を探しているんじゃなかったのか。","ENG":"I thought we were looking for intel, not money.","TWN":"我以為你在找資訊，不是錢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 그랬지.","JPN":"あっ、そうだった。","ENG":"Oh, right.","TWN":"啊，說得也是。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그나저나 수첩이라니. 차원함선이랑 안 어울리는 아날로그 감성이네.","JPN":"それにしても手帳かあ。次元艦船に似合わずアナログ式だね。","ENG":"Still, a notebook? That's pretty analog for a dimensional ship.","TWN":"話說回來，筆記本。和次元艦船很不搭的復古感。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"표지에 그려진 이 수상한 그림은 뭘까?","JPN":"表紙に描いてあるこの怪しい絵って何なのかな？","ENG":"And what's this weird drawing on the cover?","TWN":"封面畫的這奇怪的圖案是什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건 관리국 시절, 내가 속해 있던 전대의 상징일세.","JPN":"某がまだ管理局にいた頃、所属していた戦隊の象徴だ。","ENG":"That's the symbol of the division I belonged to back during the Administration days.","TWN":"這是在管理局時期，我所屬的前輩的標誌。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"진짜? 그럼 변변찮은 게 아니라 엄청 중요한 발견이잖아!","JPN":"本当？　お粗末どころかかなり重要な発見じゃん！","ENG":"Seriously?! That's not junk, that's a huge discovery!","TWN":"真的？那這不是不值錢，是超級重要的發現！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"중요한 건 안에 든 내용이지.","JPN":"大事なのは中身だろう。","ENG":"What matters is what's inside.","TWN":"重要的是裡面的內容。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내용…? 뭐라고 써져 있는데?","JPN":"中身……？　何が書いてあるの？","ENG":"Inside…? Well, what's written in it?","TWN":"內容…？寫了什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"백지. 아무것도 쓰여 있지 않아.","JPN":"白紙だ。何も書かれておらん。","ENG":"It's blank. Nothing's written.","TWN":"空白。什麼都沒寫。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"단 한 페이지도?","JPN":"たった1ページも？","ENG":"Not even a single page?","TWN":"連一頁都沒有？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"단 한 글자도.","JPN":"たった1文字もだ。","ENG":"Not even a single letter.","TWN":"連一個字都沒有。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"차원함선의 텅 빈 데이터베이스와 마찬가지의 이유겠지.","JPN":"きっと次元艦船の空っぽのデータベースと同じ理由だろう。","ENG":"Just like the ship's wiped database.","TWN":"原因大概和次元艦船裡空白的資料庫一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"모종의 정보 오염에 휘말려 기록이 말소됐을 가능성이 커.","JPN":"何らかの情報汚染に巻き込まれ、記録が抹消された可能性が高い。","ENG":"Most likely, the records were wiped out in some kind of data corruption.","TWN":"很可能捲入了某種資訊汙染，記錄被抹除了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아니면 글씨가 숨겨져 있는 게 아닐까? 특수한 용액을 써야 보인다던지!","JPN":"文字が隠されてるとかない？　特殊な溶液かけたら文字が現れるとかさ！","ENG":"Or maybe the writing's hidden! Maybe it only shows up with a special solution or something!","TWN":"會不會是字被隱藏起來了？需要用特殊的溶液才能顯現？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"망상이 지나치군. 세상에 투명한 글씨 같은 게 존재할 리가…","JPN":"大した想像力だな。そんな透明な文字なんかがあるわけ……","ENG":"That's a bit of a stretch. There's no such thing as invisible ink in real life–","TWN":"想像力太豐富了。這世界上怎麼會有那種透明的字…"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"일리 있는 가설이야.","JPN":"可能性はあるな。","ENG":"Actually, that's plausible.","TWN":"這是個很有道理的假設。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"진짜로 된다고?","JPN":"本当にできるだと？","ENG":"You're serious?","TWN":"真的可以嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"잉크 대신 무색의 화학약품으로 글씨를 쓰는 트릭이지.","JPN":"インクの代わりに無色の化学薬品で字を書くトリックだ。","ENG":"It's a trick where you write with colorless chemicals instead of ink.","TWN":"這是一種用無色的化學藥品代替墨水寫字的把戲。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"페놀트탈레인을 사용했다면, 염기성 용액에 반응할 걸세.","JPN":"フェノールフタレインを使っているとしたら、アルカリ性溶液に反応するはず。","ENG":"If it was phenolphthalein, a basic solution would make it visible.","TWN":"如果用的是酚酞，那就會和鹼性溶液反應。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"페놀… 그게 뭔데?","JPN":"フェノール……なんだそれは？","ENG":"Phenol… what now?","TWN":"酚酞…那是什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 집에 베이킹소다가 있어!","JPN":"あ、家に重曹があるよ！","ENG":"Oh! I've got baking soda at home!","TWN":"啊，家裡有小蘇打！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"돌아가서 확인해보자!","JPN":"帰って確かめてみよう！","ENG":"Let's go test it!","TWN":"回去確認看看吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아직 아무 글씨도 안 보이는군.","JPN":"何も現れないな。","ENG":"Nothing's showing up.","TWN":"沒有任何字顯現出來。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"좀 더 부어야 하나?","JPN":"もうちょっと注いだほうがいいのか？","ENG":"Should I pour more?","TWN":"要再倒多一點嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관두지. 종이가 녹겠어.","JPN":"いや、それ以上だと紙が溶けてしまうかもしれん。","ENG":"Don't. You'll melt the page.","TWN":"算了。紙都要溶解了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐어… 시도는 해 볼만 했잖아.","JPN":"まあ……確かめる価値はあったし。","ENG":"Well… it was worth a shot.","TWN":"嗯…好歹我們嘗試過了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 사전답사도 끝났으니, 내일은 본격적으로 함선 분해 작업을 시작할까?!","JPN":"じゃあ下見も終わったし、明日は本格的に艦船の分解作業に入ろうか！？","ENG":"Well, now that the scouting's done, shall we start dismantling the ship tomorrow?","TWN":"那既然事前調查結束了，明天就開始正式拆解艦船吧？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"네가 그렇게 흥분하는 모습은 처음 보는군.","JPN":"そんなに浮かれたお前は初めて見るな。","ENG":"This is the first time I've seen you this excited.","TWN":"你這麼興奮，還是第一次看到。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그, 그야 이때가 아니면 차원함선을 분해해볼 기회가 언제 또 오겠어?","JPN":"だ、だってさあ、次元艦船を分解するチャンスなんてめったにないんだよー？","ENG":"Well duh! When else am I gonna get to tear apart a dimensional ship?!","TWN":"那，那是當然，除了現在，什麼時候還有機會拆解次元艦船？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그치만… 이런 식으로 함선을 팔아 치워서 이터니움을 구한다고 해도, 먹비가 계속 내리지 않으면 그거대로 문제네.","JPN":"だけど……こうして艦船を売ってエタニウムを調達しても、墨雨が降らなかったらどうしよう。","ENG":"Still… even if we manage to sell it and get Eternium, we've got another problem if the Ink Rain doesn't come back.","TWN":"不過…就算用這種方式賣掉艦船來換永恆之金，如果墨雨一直不降臨，那也是個問題。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런 걱정은 이제 필요 없네. 내 피를 사용하면…","JPN":"その心配はもういらん。某の血を使えば……","ENG":"You won't need to worry about that. I can just use my blood…","TWN":"你不用再擔心這個了。只要使用我的血…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부는 당분간 그 피 어디 쓸 생각 하지 마.","JPN":"師匠はしばらく血使うの禁止だから。","ENG":"Nope. Master, you are not using your blood again anytime soon.","TWN":"師父你最近都別想再用那招。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"수혈도 못 받는 주제에 며칠 동안 피를 리터 단위로 흘려대니까 피부색도 좀비처럼 변했다고!","JPN":"輸血もできないくせに、ここ数日、血をリットル単位で流しちゃってさ。今肌がゾンビみたいになってるんだよ！","ENG":"Think about it. You can't get blood-infusion, you lost liters of it, and your skin's still gray like a zombie!","TWN":"你又不能輸血，這幾天流了幾公升的血，現在皮膚都變得像殭屍了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나도 동감이다.","JPN":"私も同意見だ。","ENG":"I agree.","TWN":"我也同意。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"과거로 가는 것도 중요하지만, 일단 사람부터 살고 봐야 하니까.","JPN":"過去に行くことも大事だが、人命が優先だ。","ENG":"Getting back to the past is important, but keeping you alive comes first.","TWN":"回到過去固然重要，但首先要保住性命。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 꼴이… 그 정도로 나쁜가?","JPN":"某の様子は……そこまでひどいのか？","ENG":"Do I… look that bad?","TWN":"我現在…看起來有那麼糟嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"말 나온 김에 묻겠는데, 서생. 당신은 정체가 뭐지?","JPN":"話が出たついでに聞くが……ショウ、お前は何者だ？","ENG":"Speaking of which, Seosaeng… What exactly are you?","TWN":"話說到這，我想問你，書生。你到底是誰？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"왜 당신의 피가 침식현상이 만드는 에너지를 대신할 수 있는 건지, 동료인 나도 알아야겠는데.","JPN":"なぜお前の血が侵食現象が生み出すエネルギーの代わりになれるのか、仲間である私も知りたいのだが。","ENG":"I need to understand why does your blood work in place of the energy produced by the Counterside Effect.","TWN":"為什麼你的血能代替侵蝕現象產生的能量，我也需要知道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"확실한 정보는 아니지만…","JPN":"確かな情報ではないが……","ENG":"I can't say for sure…","TWN":"雖然不是確切的資訊…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건 아마도, 내가 범이란 존재와 깊은 연관이 있기 때문일 걸세.","JPN":"それはおそらく、某が虎という存在と深い関わりがあるからだ。","ENG":"But it's probably because I'm deeply tied to the entity known as the Tiger.","TWN":"這大概，是因為我和老虎這個存在有很深的關聯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 말이 사실이라면 흥미롭네.","JPN":"その話が事実なら興味深いな。","ENG":"That's interesting if what you're saying is true.","TWN":"如果這是真的，那很有趣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신의 피에 담긴 힘은 본래 짐승이라 불리는 괴물의 것이고, 그걸 <color=#ffd34c>땅내림</color>이라 부르며 여러 생애에 걸쳐 물려받았다는 건가?","JPN":"お前の血に宿る力は本来ケモノと呼ばれる化け物のもので。<color=#ffd34c>チガカリ</color>と呼ばれるそれを、幾度かの生を経て受け継いできたということか？","ENG":"So the power in your blood originally belonged to one of those monsters called the Beasts, and you've inherited it across multiple lifetimes under something called the <color=#ffd34c>Earthbound</color>?","TWN":"你的血所蘊含的力量，原本是屬於被稱為野獸的怪物，而你將它稱為地脈之力，在好幾次的生命中繼承下來？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"환생이라는 거… 진짜로 있는 거였구나.","JPN":"転生って……本当にあったんだ。","ENG":"So reincarnation… is real after all.","TWN":"輪迴轉世…是真的存在的喔。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 사부가 똑똑한 것도 여러 번 살면서 쌓인 지식 덕분이었네! 그치?","JPN":"じゃあ師匠が賢いのは、転生で積み上げた知識のおかげだね！","ENG":"Then Master being a genius must be because he lived so many times! Right?","TWN":"那師父這麼聰明，也是因為好幾次人生累積下來的知識吧！對嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 점은 확실히 정정해두지.","JPN":"そこは確実に訂正しておこう。","ENG":"I'll have to stop you right there.","TWN":"這點我必須澄清。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 천재성은 축적된 게 아니라 타고난 걸세.","JPN":"某の天才性は蓄積されたものではなく、生まれ持ったものである。","ENG":"My genius is not recycled knowledge. It's innate.","TWN":"我的天才，不是累積下來的，而是與生俱來的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 그러셔?","JPN":"あ、そう？","ENG":"Uh-huh. Suuure.","TWN":"啊，是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관리국에 들어가기 전까진, 이전의 삶에 대해서 전혀 알지 못했어.","JPN":"管理局に入るまでは、前回の生についてまったく知らなかった。","ENG":"Before joining the Administration, I had no idea about my past lives.","TWN":"在進入管理局之前，我對我上一世的事情一無所知。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나와 내 아버지가… 그런 피를 가졌다는 사실조차 말이야.","JPN":"父と某が……そのような血を持っていることも。","ENG":"Didn't even know that… my father and I carried this blood.","TWN":"甚至不知道我和我父親…擁有那樣的血。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"기본적으로 전생의 기억까지 계승되진 않는다는 건가?","JPN":"基本的に前世の記憶までは受け継がれないということか。","ENG":"So you don't retain your memories from previous lives by default?","TWN":"所以說，前世的記憶基本上不會被繼承？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇다면 관리국은 무슨 수로 매번 당신을 찾아 영입할 수 있었던 거지?","JPN":"なら、管理局はどうやって毎回お前を探し出して、スカウトできたんだ？","ENG":"Then how did the Administration manage to find and recruit you every time?","TWN":"那管理局每次是怎麼找到你，並招募你的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그걸 <color=#ffd34c>운명</color>이라고 하더군.","JPN":"それを<color=#ffd34c>運命</color>と呼ぶらしい。","ENG":"They called it <color=#ffd34c>fate</color>.","TWN":"他們稱之為<color=#ffd34c>命運</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"운명…?","JPN":"運命……？","ENG":"Fate…?","TWN":"命運？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리 모두, 그런 걸 한 번쯤은 믿어보았지 않나.","JPN":"人は誰しも、生きながらにして一度は信じてみるものであろう？","ENG":"Haven't we all believed in something like that at least once?","TWN":"我們所有人都曾經相信過這種東西，不是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"뜻하지 않아도 얽히게 되고 마는… 그런 타고난 처지 말일세.","JPN":"意図せずとも関わってしまう……生まれたときから決まった何かを。","ENG":"That no matter what we do, we end up tangled in the same web… because that's how we were born.","TWN":"即使不願意，也無法避免糾纏在一起…那種與生俱來的境遇。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};